package com.multilanglearner.ui.vocabulary

import android.app.Application
import android.graphics.*
import android.os.Environment
import androidx.lifecycle.AndroidViewModel
import androidx.lifecycle.viewModelScope
import com.multilanglearner.data.db.entity.FavoriteWord
import com.multilanglearner.data.network.AIService
import com.multilanglearner.data.repository.FavoriteRepository
import com.multilanglearner.data.store.AIConfigStore
import dagger.hilt.android.lifecycle.HiltViewModel
import kotlinx.coroutines.Dispatchers
import kotlinx.coroutines.flow.*
import kotlinx.coroutines.launch
import java.io.File
import java.io.FileOutputStream
import javax.inject.Inject

data class VocabUiState(
    val words: List<FavoriteWord> = emptyList(),
    val generatedImageBitmap: Bitmap? = null,
    val statusText: String = ""
)

@HiltViewModel
class VocabularyViewModel @Inject constructor(
    application: Application,
    private val favoriteRepository: FavoriteRepository,
    private val aiService: AIService,
    private val aiConfigStore: AIConfigStore
) : AndroidViewModel(application) {

    private val _uiState = MutableStateFlow(VocabUiState())
    val uiState: StateFlow<VocabUiState> = _uiState.asStateFlow()

    init {
        viewModelScope.launch {
            favoriteRepository.getAll().collect { words ->
                _uiState.update { it.copy(words = words) }
            }
        }
    }

    fun deleteWord(word: FavoriteWord) {
        viewModelScope.launch { favoriteRepository.remove(word.word, word.lang) }
    }

    fun importFromClipboard() {
        // Placeholder - actual clipboard access happens in UI layer
    }

    /** Generate vocabulary image - ported from renderer.js renderSceneWithLabels() */
    fun generateImage(words: List<FavoriteWord>) {
        viewModelScope.launch(Dispatchers.Default) {
            val bitmap = renderVocabImage("我的词汇", words.map { it.word to (it.translation) })
            _uiState.update { it.copy(generatedImageBitmap = bitmap) }
        }
    }

    fun aiClassifyAndImage() {
        val words = _uiState.value.words
        if (words.isEmpty()) return

        viewModelScope.launch(Dispatchers.IO) {
            val config = aiConfigStore.config.first()
            val wordList = words.map { it.word }
            val prompt = "将以下单词按语义分组，每组给中文主题名：${wordList.joinToString(", ")}\n回复JSON：[{\"group\":\"主题名\",\"words\":[\"word1\",\"word2\"]}]，只回复JSON。"
            val result = aiService.chat(config, prompt)
            // Parse and generate images for each group
            // Simplified: just generate one image with all words
            generateImage(words)
        }
    }

    fun clearImage() { _uiState.update { it.copy(generatedImageBitmap = null) } }

    fun saveImage(bitmap: Bitmap) {
        viewModelScope.launch(Dispatchers.IO) {
            val dir = Environment.getExternalStoragePublicDirectory(Environment.DIRECTORY_PICTURES)
            dir.mkdirs()
            val file = File(dir, "vocab_${System.currentTimeMillis()}.png")
            FileOutputStream(file).use { bitmap.compress(Bitmap.CompressFormat.PNG, 100, it) }
        }
    }

    /** Canvas rendering - ported from renderer.js renderSceneWithLabels() */
    private fun renderVocabImage(title: String, wordDetails: List<Pair<String, String>>): Bitmap {
        val W = 1024; val H = 768
        val bitmap = Bitmap.createBitmap(W, H, Bitmap.Config.ARGB_8888)
        val canvas = Canvas(bitmap)

        // Background gradient
        val bgPaint = Paint().apply {
            shader = LinearGradient(0f, 0f, W.toFloat(), H.toFloat(),
                intArrayOf(0xFF667eea.toInt(), 0xFF764ba2.toInt()),
                null, Shader.TileMode.CLAMP)
        }
        canvas.drawRect(0f, 0f, W.toFloat(), H.toFloat(), bgPaint)

        // Decorative circles
        val circlePaint = Paint().apply { color = 0x1FFFFFFF; isAntiAlias = true }
        for (i in 0 until 8) {
            val cx = (Math.random() * W).toFloat()
            val cy = (Math.random() * H * 0.7).toFloat()
            val r = (40 + Math.random() * 100).toFloat()
            canvas.drawCircle(cx, cy, r, circlePaint)
        }

        // Semi-transparent overlay
        val overlayPaint = Paint().apply {
            shader = LinearGradient(0f, 0f, 0f, H.toFloat(),
                intArrayOf(0x26000000, 0x0D000000, 0x1A000000, 0x8C000000),
                floatArrayOf(0f, 0.4f, 0.6f, 1f), Shader.TileMode.CLAMP)
        }
        canvas.drawRect(0f, 0f, W.toFloat(), H.toFloat(), overlayPaint)

        // Title
        val titlePaint = Paint().apply {
            color = Color.WHITE; textSize = 24f; isAntiAlias = true; isFakeBoldText = true
            typeface = Typeface.DEFAULT_BOLD
        }
        val titleBgPaint = Paint().apply { color = 0xE65b7a5e.toInt(); isAntiAlias = true }
        val titleText = "📚 $title"
        val tw = titlePaint.measureText(titleText) + 40
        canvas.drawRoundRect(20f, 16f, 20f + tw, 64f, 24f, 24f, titleBgPaint)
        canvas.drawText(titleText, 40f, 48f, titlePaint)

        // Word cards
        val n = wordDetails.size
        val cols = minOf(3, n)
        val rows = (n + cols - 1) / cols
        val cardW = 300f; val cardH = 62f; val gapX = 16f; val gapY = 14f
        val gridW = cols * (cardW + gapX) - gapX
        val gridH = rows * (cardH + gapY) - gapY
        val ox = (W - gridW) / 2
        val oy = H - gridH - 40

        val cardBgPaint = Paint().apply { color = 0xEBFFFFFF.toInt(); isAntiAlias = true }
        val barPaint = Paint().apply { color = 0xFF5b7a5e.toInt(); isAntiAlias = true }
        val numPaint = Paint().apply { color = Color.WHITE; textSize = 11f; isAntiAlias = true; textAlign = Paint.Align.CENTER; isFakeBoldText = true }
        val wordPaint = Paint().apply { color = 0xFF1a1a1a.toInt(); textSize = 20f; isAntiAlias = true; isFakeBoldText = true }
        val transPaint = Paint().apply { color = 0xFF5b7a5e.toInt(); textSize = 14f; isAntiAlias = true }

        for (i in 0 until n) {
            val col = i % cols; val row = i / cols
            val x = ox + col * (cardW + gapX)
            val y = oy + row * (cardH + gapY)

            canvas.drawRoundRect(x, y, x + cardW, y + cardH, 12f, 12f, cardBgPaint)
            canvas.drawRoundRect(x, y, x + 6, y + cardH, 3f, 3f, barPaint)

            // Number circle
            canvas.drawCircle(x + 22, y + 20, 10f, barPaint)
            canvas.drawText((i + 1).toString(), x + 22, y + 24, numPaint)

            // Word
            canvas.drawText(wordDetails[i].first, x + 40, y + 26, wordPaint)
            // Translation
            val trans = wordDetails[i].second.take(24)
            canvas.drawText(trans, x + 40, y + 50, transPaint)
        }

        // Watermark
        val wmPaint = Paint().apply { color = 0x80FFFFFF.toInt(); textSize = 11f; isAntiAlias = true; textAlign = Paint.Align.CENTER }
        canvas.drawText("多语言视频学习 · 词汇场景图", W / 2f, H - 10f, wmPaint)

        return bitmap
    }
}

